import{_ as i,y as o,a as g,o as a,ag as h,D as c}from"./chunks/framework.C2qfZH9T.js";const b=JSON.parse('{"title":"GDPR","description":"","frontmatter":{},"headers":[],"relativePath":"configure/gdpr.md","filePath":"configure/gdpr.md","lastUpdated":1775320633000}'),r={name:"configure/gdpr.md"};function u(e,n,l,p,s,d){const t=o("ImagePopup");return a(),g("div",null,[n[0]||(n[0]=h('<h1 id="gdpr" tabindex="-1">GDPR <a class="header-anchor" href="#gdpr" aria-label="Permalink to &quot;GDPR&quot;">​</a></h1><p>VNS cung cấp các tính năng tuân thủ GDPR (Quy định chung về bảo vệ dữ liệu) cần thiết để giúp doanh nghiệp đảm bảo quyền riêng tư và minh bạch dữ liệu cho khách hàng của mình. Dưới đây là các phần chính có sẵn các cài đặt và tùy chọn liên quan đến GDPR:</p><h2 id="bat-cai-đat-tuan-thu-gdpr" tabindex="-1">Bật cài đặt tuân thủ GDPR <a class="header-anchor" href="#bat-cai-đat-tuan-thu-gdpr" aria-label="Permalink to &quot;Bật cài đặt tuân thủ GDPR&quot;">​</a></h2><p>Để thêm, hãy đi tới Bảng quản trị và nhấp vào <strong>Định cấu hình &gt;&gt; GDPR &gt;&gt; Bật GDPR</strong>.<br> Phần này trao quyền cho chủ cửa hàng định cấu hình các chính sách liên quan đến GDPR và quản lý hiệu quả các yêu cầu dữ liệu khách hàng. Các tính năng chính bao gồm:</p><p>Nút - <strong>Yêu cầu GDPR</strong> xuất hiện trên trang hồ sơ của khách hàng trong giao diện cửa hàng.</p><ul><li>Xử lý yêu cầu xóa hoặc cập nhật dữ liệu của khách hàng.</li></ul>',6)),c(t,{src:"/images/configure/gdpr-agreement.png",alt:"Enable GDPR Compliance Settings"}),n[1]||(n[1]=h('<p>Sau đó, nhấp vào nút <strong>Lưu cấu hình</strong>.</p><h2 id="gdpr-thoa-thuan" tabindex="-1">GDPR Thỏa thuận <a class="header-anchor" href="#gdpr-thoa-thuan" aria-label="Permalink to &quot;GDPR Thỏa thuận&quot;">​</a></h2><p>Để thêm, hãy đi tới Bảng điều khiển quản trị và nhấp vào <strong>Định cấu hình &gt;&gt; GDPR &gt;&gt; Kích hoạt Thỏa thuận khách hàng</strong>.<br> Nút Thỏa thuận GDPR được sử dụng để nhận được sự đồng ý rõ ràng từ khách hàng trước khi họ tiến hành đăng ký tài khoản, thanh toán hoặc các hành động khác liên quan đến dữ liệu. Nó đảm bảo:</p><ul><li>UNgười dùng thừa nhận và chấp nhận chính sách bảo mật của cửa hàng.</li><li>Consent được ghi nhận để tuân thủ pháp luật.</li></ul><p>Các trường cần cung cấp trong phần Thỏa thuận GDPR:</p><ul><li><strong>Nhãn hộp kiểm thỏa thuận</strong> – Tôi đồng ý với các điều khoản và điều kiện cũng như chính sách quyền riêng tư.</li><li><strong>Nội dung thỏa thuận</strong> – Bằng cách chọn hộp này, bạn đồng ý xử lý dữ liệu cá nhân của mình theo chính sách bảo mật tuân thủ GDPR của chúng tôi.</li></ul>',6)),c(t,{src:"/images/configure/gdpr-agreement2.png",alt:"GDPR Agreement Settings"}),n[2]||(n[2]=h('<p>Sau đó, nhấp vào nút <strong>Lưu cấu hình</strong>.</p><h2 id="cookie-cai-đat-thong-bao" tabindex="-1">Cookie Cài đặt thông báo <a class="header-anchor" href="#cookie-cai-đat-thong-bao" aria-label="Permalink to &quot;Cookie Cài đặt thông báo&quot;">​</a></h2><p>Để thêm, hãy đi tới Bảng quản trị và nhấp vào <strong>Định cấu hình &gt;&gt; GDPR &gt;&gt; Bật thông báo cookie</strong>.<br> Phần này cho phép chủ cửa hàng định cấu hình cách hiển thị thông báo cookie cho người dùng. Các cài đặt chính bao gồm:</p><ul><li><p><strong>Vị trí hiển thị khối cookie</strong> – Xác định vị trí thông báo cookie sẽ xuất hiện trên trang. Tùy chọn có sẵn:</p><ul><li>Từ dưới bên trái</li><li>Dưới cùng bên phải</li><li>Trên cùng bên trái</li><li>Trên cùng bên phải</li><li>Ctrung tâm</li></ul></li><li><p><strong>Mã định danh khối tĩnh</strong> – Chỉ định một khối tĩnh tùy chỉnh để hiển thị trong thông báo cookie.</p></li><li><p><strong>Description</strong> – Trường văn bản có thể tùy chỉnh để mô tả mục đích của cookie, chi tiết về quyền riêng tư và cách người dùng có thể quản lý tùy chọn của họ.</p></li></ul>',4)),c(t,{src:"/images/configure/cookies-position.png",alt:"Cookie Notice Settings"}),n[3]||(n[3]=h('<p>Sau đó, nhấp vào nút <strong>Lưu cấu hình</strong>.</p><h2 id="quan-ly-tuy-chon-cookie-cua-ban" tabindex="-1">Quản lý tùy chọn cookie của bạn <a class="header-anchor" href="#quan-ly-tuy-chon-cookie-cua-ban" aria-label="Permalink to &quot;Quản lý tùy chọn cookie của bạn&quot;">​</a></h2><p>Phần này cho phép người dùng cá nhân hóa cài đặt cookie dựa trên sở thích của họ. Các danh mục có sẵn bao gồm:</p><ul><li><p><strong>Cực kỳ cần thiết</strong> – Cần có các cookie thiết yếu để trang web hoạt động bình thường, chẳng hạn như quản lý phiên và các tính năng bảo mật. Không thể bị vô hiệu hóa.</p></li><li><p><strong>Tương tác &amp; chức năng cơ bản</strong> – Hỗ trợ tương tác của người dùng, chẳng hạn như tính năng trò chuyện, gửi biểu mẫu và cải tiến điều hướng.</p></li><li><p><strong>Cải tiến trải nghiệm</strong> – Cải thiện trải nghiệm người dùng bằng cách ghi nhớ các tùy chọn, chẳng hạn như lựa chọn ngôn ngữ hoặc bố cục tùy chỉnh.</p></li><li><p><strong>Measurements</strong> – Phân tích cookie để theo dõi hiệu suất trang web, hành vi của người dùng và hiểu biết về lưu lượng truy cập để tối ưu hóa.</p></li><li><p><strong>Nhắm mục tiêu &amp; Quảng cáo</strong> – Cookie được sử dụng để tiếp thị được cá nhân hóa, nhắm mục tiêu quảng cáo và nhắm mục tiêu lại dựa trên hành vi và sở thích của người dùng.</p></li></ul><p>Sau đó, nhấp vào nút <strong>Lưu cấu hình</strong>.</p>',5))])}const _=i(r,[["render",u]]);export{b as __pageData,_ as default};
